func catLinkClass(active bool) string {
	base := "block px-3 py-1.5 rounded text-sm transition-colors "
	if active {
		return base + "font-semibold"
	}
	return base + "text-slate-600 hover:bg-slate-100"
}

func selectedCatName(cats []model.Category, id int64) string {
	for _, c := range cats {
		if c.ID == id {
			return c.Name
		}
	}
	return ""
}

